+
+    // ── insert_hash edge cases ──────────────────────────────────────
+
+    #[test]
+    fn insert_hash_zero() {
+        let mut hll = HyperLogLog::new();
+        hll.insert_hash(0);
+        assert_eq!(hll.total_inserts(), 1);
+        assert!(hll.cardinality() >= 1);
+    }
+
+    #[test]
+    fn insert_hash_max() {
